SELECT * FROM OUTSOURCE_TRANSPORT_SETTLEMENT
WHERE 是否删除 = 0

    AND 合同编号 = #{contractId}


    AND 合同单号 = #{contractNo}


    AND 状态 = #{status}


    AND 承运方名称 LIKE CONCAT('%', #{carrierName}, '%')


    AND 结算单单号 LIKE CONCAT('%', #{settlementNo}, '%')


    AND 结算周期起 >= #{startDate}


    AND 结算周期止 <= #{endDate}


    AND 付款方向 = #{settlementDirection}


    AND 合同编号 IS NULL

ORDER BY 创建时间 DESC

SELECT COUNT(1) FROM OUTSOURCE_TRANSPORT_SETTLEMENT
WHERE 是否删除 = 0

    AND 合同编号 = #{contractId}


    AND 合同单号 = #{contractNo}


    AND 状态 = #{status}


    AND 承运方名称 LIKE CONCAT('%', #{carrierName}, '%')


    AND 结算单单号 LIKE CONCAT('%', #{settlementNo}, '%')


    AND 结算周期起 >= #{startDate}


    AND 结算周期止 <= #{endDate}


    AND 付款方向 = #{settlementDirection}


    AND 合同编号 IS NULL
